const nocodb_base = 'https://whizz.aiingo.com';
const nocodb_token = 'nc_pat_n5dMpFolDUQNtkCWGiCJnX45xXWUoFnZdsQkwEyF';
const leads_table_id = 'mvg6rcw0ia5qqrx';
return [{ json: { nocodb_base, nocodb_token, leads_table_id } }];

const body = $('Webhook').first().json.body || $('Webhook').first().json;
const payload = body.payload || body;
const triggerEvent = body.triggerEvent || body.trigger_event || '';

// Extract phone
let phone = '';
if (payload.responses?.phone?.value) {
  phone = payload.responses.phone.value;
} else if (payload.attendees && payload.attendees[0]) {
  const att = payload.attendees[0];
  phone = att.phone || att.customFields?.phone || '';
}

// Normalize phone: strip non-digits, remove leading +
phone = String(phone).replace(/[^0-9+]/g, '').replace(/^\+/, '');
if (phone.startsWith('00')) phone = phone.slice(2);

const isCancelled = triggerEvent === 'BOOKING_CANCELLED' || triggerEvent === 'booking.cancelled';
const startTime = payload.startTime || '';
const uid = payload.uid || '';
const title = payload.title || '';

return [{ json: { phone, isCancelled, startTime, uid, title, triggerEvent } }];

const parse = $('Code · Parse payload').first().json;
const settings = $('Code · Settings').first().json;
const result = $input.first().json;
const leads = result.list || [];
const lead = leads[0] || null;

if (!lead) {
  return [{ json: { _skip: true, reason: 'Lead not found for phone: ' + parse.phone } }];
}

let updateBody = { Id: lead.Id };
if (parse.isCancelled) {
  updateBody.Stage = 'new';
  updateBody.BookingTime = '';
} else {
  updateBody.Stage = 'consultation_booked';
  updateBody.BookingTime = parse.startTime;
  updateBody['Follow up 1'] = 'No';
  updateBody['Follow up 2'] = 'No';
  updateBody['Follow up 3'] = 'No';
}

return [{ json: { ...parse, leadId: lead.Id, updateBody, _skip: false, nocodb_base: settings.nocodb_base, nocodb_token: settings.nocodb_token, leads_table_id: settings.leads_table_id } }];
